import { useState } from "react";

const tasks=[
 { id:"T-001",equipment:"MRI Scanner #A12",hospital:"City General Hospital",priority:"High",deadline:"2024-04-15",status:"Pending",description:"Annual calibration and safety check",image:"data:image/jpeg;base64,"},
  { id:"T-002",equipment:"Ventilator #B05",hospital:"Apollo Medical Center",priority:"Critical",deadline:"2024-04-12",status:"In Progress",description:"Alarm system malfunction — urgent fix needed",image:"data:image/webp;base64,"},
  { id:"T-003",equipment:"Defibrillator #C07",hospital:"City General Hospital",priority:"High",deadline:"2024-04-10",status:"In Progress",description:"Replace battery pack and test output",image:"data:image/jpeg;base64,"},
  { id:"T-004",equipment:"Infusion Pump #G01",hospital:"Sunrise Hospital",priority:"Medium",deadline:"2024-04-20",status:"Pending",description:"Flow rate calibration",image:"data:image/jpeg;base64,"},
  { id:"T-005",equipment:"X-Ray Machine #E01",hospital:"Apollo Medical Center",priority:"Low",deadline:"2024-04-08",status:"Completed",description:"Software firmware update",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSEBrljVMKXHguN5-b4rrm9OLgXPQlHPWCgpQ&s"},
  { id:"T-006",equipment:"CT Scanner #D02",hospital:"Metro Hospital",priority:"High",deadline:"2024-04-18",status:"Pending",description:"Cooling system inspection",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRnAjAk9dPxLAzqWrCgdrSIqUfx9ucfN8eQoA&s"},
  { id:"T-007",equipment:"ECG Monitor #H11",hospital:"Sunrise Hospital",priority:"Medium",deadline:"2024-04-22",status:"Pending",description:"Lead calibration check",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRJPrz4pCzF2OUaFQA8rvsoMZCk0oSC9hlj2A&s"},
  { id:"T-008",equipment:"Ultrasound Machine #U05",hospital:"Care Hospital",priority:"High",deadline:"2024-04-11",status:"In Progress",description:"Image resolution issue",image:"data:image/jpeg;base64,"},
  { id:"T-009",equipment:"Patient Monitor #P01",hospital:"City General Hospital",priority:"Low",deadline:"2024-04-25",status:"Pending",description:"Sensor replacement",image:"data:image/jpeg;base64,"},
  { id:"T-010",equipment:"Anesthesia Machine #AN03",hospital:"Metro Hospital",priority:"Critical",deadline:"2024-04-09",status:"In Progress",description:"Gas pressure issue",image:"data:image/jpeg;base64,"},
  { id:"T-011",equipment:"Dialysis Machine #DL09",hospital:"Apollo Medical Center",priority:"High",deadline:"2024-04-14",status:"Pending",description:"Pump pressure calibration",image:"data:image/jpeg;base64,"},
  { id:"T-012",equipment:"Ventilator #B09",hospital:"Care Hospital",priority:"Critical",deadline:"2024-04-13",status:"Pending",description:"Airflow sensor malfunction",image:"data:image/webp;base64,"},
  { id:"T-013",equipment:"Defibrillator #C11",hospital:"Metro Hospital",priority:"Medium",deadline:"2024-04-21",status:"Pending",description:"Battery test required",image:"data:image/jpeg;base64,"},
  { id:"T-014",equipment:"Infusion Pump #G08",hospital:"Sunrise Hospital",priority:"Low",deadline:"2024-04-23",status:"Pending",description:"Routine inspection",image:"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSNRNpnMYd0ARq9VHBrbXgf4Jkg3sWOIY0RnQ&s"},
  { id:"T-015",equipment:"MRI Scanner #A18",hospital:"City General Hospital",priority:"High",deadline:"2024-04-17",status:"In Progress",description:"Magnet cooling system check",image:"data:image/jpeg;base64,"},
  { id:"T-016",equipment:"X-Ray Machine #E04",hospital:"Care Hospital",priority:"Medium",deadline:"2024-04-26",status:"Pending",description:"Detector alignment check",image:"data:image/jpeg;base64,"},
  { id:"T-017",equipment:"ECG Monitor #H21",hospital:"Metro Hospital",priority:"Low",deadline:"2024-04-24",status:"Pending",description:"Software patch update",image:"data:image/jpeg;base64,"},
  { id:"T-018",equipment:"CT Scanner #D05",hospital:"Apollo Medical Center",priority:"High",deadline:"2024-04-19",status:"Pending",description:"Radiation calibration",image:"data:image/jpeg;base64,"},
];


const priorityStyle={
Critical:"bg-red-100 text-red-600",
High:"bg-orange-100 text-orange-600",
Medium:"bg-yellow-100 text-yellow-600",
Low:"bg-green-100 text-green-600"
};

const statusStyle={
Pending:"bg-gray-200 text-gray-700",
"In Progress":"bg-blue-200 text-blue-700",
Completed:"bg-emerald-200 text-emerald-700"
};

export default function TaskList({onNavigate}){

const[search,setSearch]=useState("");
const[status,setStatus]=useState("All");
const[priority,setPriority]=useState("All");
const[expanded,setExpanded]=useState(null);
const[sort,setSort]=useState(false);

let filtered=tasks.filter(t=>
(status==="All"||t.status===status)&&
(priority==="All"||t.priority===priority)&&
(t.equipment.toLowerCase().includes(search.toLowerCase())||
t.hospital.toLowerCase().includes(search.toLowerCase()))
);

if(sort) filtered=[...filtered].sort((a,b)=>new Date(a.deadline)-new Date(b.deadline));

const completed=tasks.filter(t=>t.status==="Completed").length;
const open=tasks.length-completed;
const critical=tasks.filter(t=>t.priority==="Critical").length;
const progress=(completed/tasks.length)*100;

return(

<div className="min-h-screen relative bg-gradient-to-br from-[#0f172a] via-[#1e3a8a] to-[#60a5fa]">

<div className="absolute inset-0 bg-[radial-gradient(circle_at_top_left,rgba(255,255,255,0.18),transparent_40%)]"></div>

<div className="relative max-w-7xl mx-auto px-6 py-8">

<div className="flex justify-between mb-6 text-white">

<div>
<h1 className="text-2xl font-bold">Maintenance Tasks</h1>
<p className="text-sm opacity-80">Manage assigned repair tasks</p>
</div>

<button onClick={()=>setSort(!sort)} className="px-4 py-2 bg-white text-blue-700 rounded-lg">
Sort by Deadline
</button>

</div>

<div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">

{[
["Total Tasks",tasks.length,""],
["Open Tasks",open,"text-blue-600"],
["Critical",critical,"text-red-600"],
["Completed",completed,"text-emerald-600"]
].map(([t,v,c])=>(
<div key={t} className="bg-white rounded-xl p-4 shadow">
<p className="text-xs text-gray-500">{t}</p>
<p className={`text-xl font-bold ${c}`}>{v}</p>
</div>
))}

</div>

<div className="bg-white rounded-xl p-4 shadow mb-6">
<p className="text-sm text-gray-600 mb-2">Completion</p>
<div className="w-full bg-gray-200 h-2 rounded-full">
<div style={{width:`${progress}%`}} className="h-2 rounded-full bg-blue-600"/>
</div>
</div>

<div className="grid md:grid-cols-3 gap-3 mb-6">

<input
value={search}
onChange={e=>setSearch(e.target.value)}
placeholder="Search equipment or hospital..."
className="px-4 py-2 border rounded-lg"
/>

<select value={status} onChange={e=>setStatus(e.target.value)} className="px-4 py-2 border rounded-lg">
<option>All</option>
<option>Pending</option>
<option>In Progress</option>
<option>Completed</option>
</select>

<select value={priority} onChange={e=>setPriority(e.target.value)} className="px-4 py-2 border rounded-lg">
<option>All</option>
<option>Critical</option>
<option>High</option>
<option>Medium</option>
<option>Low</option>
</select>

</div>

<div className="grid md:grid-cols-3 gap-6">

{filtered.map(t=>(

<div key={t.id} className="bg-white rounded-2xl shadow p-5 hover:shadow-xl transition">

<div className="h-48 overflow-hidden rounded-lg mb-4">
<img src={t.image} className="w-full h-full object-cover"/>
</div>

<div className="flex flex-wrap gap-2 items-center">
<p className="font-semibold">{t.equipment}</p>
<span className={`text-xs px-2 py-1 rounded ${priorityStyle[t.priority]}`}>{t.priority}</span>
<span className={`text-xs px-2 py-1 rounded ${statusStyle[t.status]}`}>{t.status}</span>
</div>

<p className="text-sm text-gray-500">{t.hospital}</p>

{expanded===t.id&&(
<p className="text-sm text-gray-600 mt-2">{t.description}</p>
)}

<button onClick={()=>setExpanded(expanded===t.id?null:t.id)} className="text-xs text-blue-600 mt-2">
{expanded===t.id?"Hide":"View"} details
</button>

<div className="flex justify-between mt-4">

<p className="text-xs text-gray-400">{t.deadline}</p>

{t.status!=="Completed"&&(
<button onClick={()=>onNavigate("updatetask")} className="px-4 py-2 bg-blue-600 text-white rounded-lg">
Update
</button>
)}

</div>

</div>

))}

</div>

</div>
</div>
);
}
